def solution(arr):
    if not arr:
        return arr

    # Separate positive and negative numbers
    negatives = [abs(x) for x in arr if x < 0]
    positives = [x for x in arr if x >= 0]

    # Sort negatives by absolute value (will reverse later)
    if negatives:
        max_neg = max(negatives)
        for exp in range(len(str(max_neg))):
            negatives = counting_sort_by_digit(negatives, exp)
        # Convert back to negative and reverse to get correct order
        negatives = [-x for x in negatives[::-1]]

    # Sort positives
    if positives:
        max_pos = max(positives)
        for exp in range(len(str(max_pos))):
            positives = counting_sort_by_digit(positives, exp)

    return negatives + positives

def counting_sort_by_digit(arr, exp):
    n = len(arr)
    output = [0] * n
    count = [0] * 10

    for num in arr:
        count[(num // (10 ** exp)) % 10] += 1

    for i in range(1, 10):
        count[i] += count[i - 1]

    for i in range(n - 1, -1, -1):
        digit = (arr[i] // (10 ** exp)) % 10
        output[count[digit] - 1] = arr[i]
        count[digit] -= 1

    return output

